# ジェネレーター関数（yield で値を返しつつ状態を保持）
def count_up(start: int = 0):
    while True:
        yield start
        start += 1

counter = count_up()
next(counter)  # 0
next(counter)  # 1
next(counter)  # 2

# 有限ジェネレーター
def fibonacci(n: int):
    a, b = 0, 1
    for _ in range(n):
        yield a
        a, b = b, a + b

list(fibonacci(8))  # [0,1,1,2,3,5,8,13]

# yield from（サブジェネレーターに委譲）
def chain(*iterables):
    for it in iterables:
        yield from it

list(chain([1,2], [3,4], [5,6]))  # [1,2,3,4,5,6]

